sql:
SELECT AVG(net_profit) AS average_net_profit
FROM revenue
WHERE net_profit > 100;

SELECT name, total_trips
FROM customers
WHERE total_trips = (SELECT MAX(total_trips) FROM customers);

SELECT COUNT(DISTINCT customer_id) AS customer_count
FROM transactions
WHERE city = 'New York';

SELECT customer_id, total_trips
FROM customers
ORDER BY total_trips DESC;

SELECT AVG(total_amount) AS average_total_amount
FROM transactions
WHERE date_of_travel BETWEEN date('now','-30 days') AND date('now');

